import { deriveTrainingSampleCount } from "../config/settings.js";
import { generateJuliaParameters } from "./sampling.js";
import { renderJuliaFeatureVectorForTraining } from "./features.js";
import type { TrainingSample, TrainingSettings } from "../types/settings.js";

export function generateTrainingSamples(settings: TrainingSettings): TrainingSample[] {
  const sampleCount = deriveTrainingSampleCount(settings);
  const parameters = generateJuliaParameters(settings.randomSeed, sampleCount);
  const samples: TrainingSample[] = [];

  for (let sampleIndex = 0; sampleIndex < sampleCount; sampleIndex += 1) {
    const parameter = parameters[sampleIndex];
    if (!parameter) {
      throw new Error(`Missing Julia parameter for sample index ${sampleIndex}.`);
    }

    samples.push({
      sampleIndex,
      parameter,
      featureVector: renderJuliaFeatureVectorForTraining(parameter, settings),
    });
  }

  return samples;
}

import { getSquaredEuclideanDistance } from "./distance.js";
import type { SomCell, TrainingSample } from "../types/settings.js";

export function findBestMatchingUnit(
  cells: SomCell[],
  sample: TrainingSample,
): SomCell {
  const initialCell = cells[0];
  if (!initialCell) {
    throw new Error("Cannot find BMU without SOM cells.");
  }

  let bestCell = initialCell;
  let bestDistance = getSquaredEuclideanDistance(bestCell.prototypeVector, sample.featureVector);

  for (let index = 1; index < cells.length; index += 1) {
    const cell = cells[index];
    if (!cell) {
      continue;
    }

    const distance = getSquaredEuclideanDistance(cell.prototypeVector, sample.featureVector);
    if (distance < bestDistance || (distance === bestDistance && cell.index < bestCell.index)) {
      bestCell = cell;
      bestDistance = distance;
    }
  }

  return bestCell;
}

export function getSquareGridDistance(
  fromX: number,
  fromY: number,
  toX: number,
  toY: number,
): number {
  const dx = fromX - toX;
  const dy = fromY - toY;
  return Math.sqrt(dx * dx + dy * dy);
}

import { JULIA_PARAMETER_BOUNDS } from "./constants.js";
import { XorShift128 } from "../rng/xorshift128.js";
import type { ComplexBounds, ComplexParameter } from "../types/settings.js";

function interpolate(min: number, max: number, t: number): number {
  return min + (max - min) * t;
}

export function sampleJuliaParameter(
  rng: XorShift128,
  bounds: ComplexBounds = JULIA_PARAMETER_BOUNDS,
): ComplexParameter {
  return {
    real: interpolate(bounds.minReal, bounds.maxReal, rng.nextFloat()),
    imaginary: interpolate(bounds.minImaginary, bounds.maxImaginary, rng.nextFloat()),
  };
}

export function generateJuliaParameters(
  seed: string,
  count: number,
  bounds: ComplexBounds = JULIA_PARAMETER_BOUNDS,
): ComplexParameter[] {
  const rng = new XorShift128(seed);
  const parameters: ComplexParameter[] = [];

  for (let index = 0; index < count; index += 1) {
    parameters.push(sampleJuliaParameter(rng, bounds));
  }

  return parameters;
}

