import { useEffect, useMemo, useRef } from "preact/hooks";
import type { ComplexParameter, SomCell, SomTrainingResult } from "@asimov/minimal-shared";
import {
  getCanvasSize,
  getCellCenter,
  getClosestCellAtPoint,
  getInterpolatedParameterAtPoint,
  type Point2D,
} from "./map-geometry.js";

function clampByte(value: number): number {
  return Math.max(0, Math.min(255, Math.round(value)));
}

function drawPrototypeImage(
  context: CanvasRenderingContext2D,
  cell: SomCell,
  x: number,
  y: number,
  width: number,
  height: number,
  featureWidth: number,
  featureHeight: number,
  clipPath?: Path2D,
): void {
  const imageData = context.createImageData(featureWidth, featureHeight);

  for (let index = 0; index < imageData.data.length; index += 4) {
    const vectorIndex = Math.floor(index / 4);
    const value = cell.prototypeVector[vectorIndex] ?? 0;
    const channel = clampByte(value * 255);
    imageData.data[index] = channel;
    imageData.data[index + 1] = channel;
    imageData.data[index + 2] = channel;
    imageData.data[index + 3] = 255;
  }

  const bitmapCanvas = document.createElement("canvas");
  bitmapCanvas.width = featureWidth;
  bitmapCanvas.height = featureHeight;
  const bitmapContext = bitmapCanvas.getContext("2d");
  if (!bitmapContext) {
    return;
  }

  bitmapContext.putImageData(imageData, 0, 0);

  context.save();
  if (clipPath) {
    context.clip(clipPath);
  }
  context.imageSmoothingEnabled = false;
  context.drawImage(bitmapCanvas, x, y, width, height);
  context.restore();
}

function createHexPath(center: Point2D, radius: number): Path2D {
  const path = new Path2D();
  for (let pointIndex = 0; pointIndex < 6; pointIndex += 1) {
    const angle = (Math.PI / 180) * (60 * pointIndex - 30);
    const x = center.x + radius * Math.cos(angle);
    const y = center.y + radius * Math.sin(angle);
    if (pointIndex === 0) {
      path.moveTo(x, y);
    } else {
      path.lineTo(x, y);
    }
  }
  path.closePath();
  return path;
}

function getCanvasPoint(
  canvas: HTMLCanvasElement,
  event: MouseEvent,
): Point2D {
  const rect = canvas.getBoundingClientRect();
  return {
    x: ((event.clientX - rect.left) / rect.width) * canvas.width,
    y: ((event.clientY - rect.top) / rect.height) * canvas.height,
  };
}

export function SomMapCanvas(props: {
  result: SomTrainingResult | null;
  selectedCellIndex: number | null;
  highlightedCellIndex: number | null;
  onSelectCell: (cellIndex: number | null) => void;
  onHoverParameter: (parameter: ComplexParameter | null) => void;
}): preact.JSX.Element {
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const cellWidth = props.result?.settings.featureWidth ?? 28;
  const cellHeight = props.result?.settings.featureHeight ?? 28;

  const canvasSize = useMemo(() => {
    if (!props.result) {
      return { x: 480, y: 480 };
    }
    return getCanvasSize(props.result, props.result.settings.topology, cellWidth, cellHeight);
  }, [props.result, cellWidth, cellHeight]);

  useEffect(() => {
    const canvas = canvasRef.current;
    const result = props.result;
    if (!canvas) {
      return;
    }

    const context = canvas.getContext("2d");
    if (!context) {
      return;
    }

    context.clearRect(0, 0, canvas.width, canvas.height);
    context.fillStyle = "#f3ede1";
    context.fillRect(0, 0, canvas.width, canvas.height);

    if (!result) {
      context.fillStyle = "#6c7b89";
      context.font = '16px "IBM Plex Sans", sans-serif';
      context.fillText("Train the SOM to render the map.", 24, 48);
      return;
    }

    const topology = result.settings.topology;
    if (topology === "squares") {
      for (const cell of result.cells) {
        const x = cell.x * cellWidth;
        const y = cell.y * cellHeight;
        drawPrototypeImage(
          context,
          cell,
          x,
          y,
          cellWidth,
          cellHeight,
          result.settings.featureWidth,
          result.settings.featureHeight,
        );
        const isSelected = cell.index === props.selectedCellIndex;
        const isHighlighted = cell.index === props.highlightedCellIndex;
        context.strokeStyle = isSelected
          ? "#cb5a2e"
          : isHighlighted
            ? "#1457a6"
            : "rgba(16, 35, 58, 0.18)";
        context.lineWidth = isSelected ? 3 : isHighlighted ? 2.5 : 1;
        context.strokeRect(x + 0.5, y + 0.5, cellWidth - 1, cellHeight - 1);
      }
      return;
    }

    const radius = Math.min(cellWidth, cellHeight) / 2;
    for (const cell of result.cells) {
      const center = getCellCenter("hexagons", cell, cellWidth, cellHeight);
      const path = createHexPath(center, radius - 1);
      drawPrototypeImage(
        context,
        cell,
        center.x - cellWidth / 2,
        center.y - cellHeight / 2,
        cellWidth,
        cellHeight,
        result.settings.featureWidth,
        result.settings.featureHeight,
        path,
      );
      const isSelected = cell.index === props.selectedCellIndex;
      const isHighlighted = cell.index === props.highlightedCellIndex;
      context.strokeStyle = isSelected
        ? "#cb5a2e"
        : isHighlighted
          ? "#1457a6"
          : "rgba(16, 35, 58, 0.2)";
      context.lineWidth = isSelected ? 3 : isHighlighted ? 2.5 : 1.25;
      context.stroke(path);
    }
  }, [
    props.result,
    props.selectedCellIndex,
    props.highlightedCellIndex,
    canvasSize.x,
    canvasSize.y,
    cellWidth,
    cellHeight,
  ]);

  useEffect(() => {
    const canvas = canvasRef.current;
    const result = props.result;
    if (!canvas || !result) {
      return;
    }
    const activeCanvas = canvas;
    const activeResult = result;

    function handleMove(event: MouseEvent): void {
      const point = getCanvasPoint(activeCanvas, event);
      props.onHoverParameter(getInterpolatedParameterAtPoint(activeResult, point, cellWidth, cellHeight));
    }

    function handleLeave(): void {
      props.onHoverParameter(null);
    }

    function handleClick(event: MouseEvent): void {
      const point = getCanvasPoint(activeCanvas, event);
      const cell = getClosestCellAtPoint(activeResult, point, cellWidth, cellHeight);
      props.onSelectCell(cell?.index ?? null);
    }

    activeCanvas.addEventListener("mousemove", handleMove);
    activeCanvas.addEventListener("mouseleave", handleLeave);
    activeCanvas.addEventListener("click", handleClick);

    return () => {
      activeCanvas.removeEventListener("mousemove", handleMove);
      activeCanvas.removeEventListener("mouseleave", handleLeave);
      activeCanvas.removeEventListener("click", handleClick);
    };
  }, [props, cellWidth, cellHeight]);

  return (
    <div className="canvas-frame canvas-frame--map">
      <canvas
        ref={canvasRef}
        className="canvas canvas--map"
        width={Math.ceil(canvasSize.x)}
        height={Math.ceil(canvasSize.y)}
      />
    </div>
  );
}

