16	export function getSmoothEscapeValue(
17	  startReal: number,
18	  startImaginary: number,
19	  parameter: ComplexParameter,
20	  maxIterations: number,
21	): number {
22	  let real = startReal;
23	  let imaginary = startImaginary;
24	
25	  for (let iteration = 0; iteration < maxIterations; iteration += 1) {
26	    const nextReal = real * real - imaginary * imaginary + parameter.real;
27	    const nextImaginary = 2 * real * imaginary + parameter.imaginary;
28	
29	    real = nextReal;
30	    imaginary = nextImaginary;
31	
32	    const magnitudeSquared = real * real + imaginary * imaginary;
33	    if (magnitudeSquared > JULIA_BAILOUT_RADIUS * JULIA_BAILOUT_RADIUS) {
34	      const magnitude = Math.sqrt(magnitudeSquared);
35	      const smoothIteration =
36	        iteration + 1 - Math.log(Math.log(Math.max(magnitude, JULIA_BAILOUT_RADIUS))) / LOG_2;
37	
38	      return clampToUnitInterval(smoothIteration / maxIterations);
39	    }
40	  }
