    13	export function getHexGridDistance(
    14	  fromX: number,
    15	  fromY: number,
    16	  toX: number,
    17	  toY: number,
    18	): number {
    19	  const from = offsetToAxial(fromX, fromY);
    20	  const to = offsetToAxial(toX, toY);
    21	
    22	  const dq = from.q - to.q;
    23	  const dr = from.r - to.r;
