 1	import { APP_ALGORITHM_VERSION } from "../config/defaults.js";
 2	import type { ReproducibilityFingerprint, TrainingSettings } from "../types/settings.js";
 3	
 4	function stableJsonValue(value: unknown): string {
 5	  if (value === null) {
 6	    return "null";
 7	  }
 8	
 9	  switch (typeof value) {
10	    case "number":
11	      if (!Number.isFinite(value)) {
12	        throw new Error("Non-finite numbers are not supported in fingerprint input.");
13	      }
14	      return JSON.stringify(value);
15	    case "boolean":
16	      return value ? "true" : "false";
17	    case "string":
18	      return JSON.stringify(value);
19	    case "object":
20	      if (Array.isArray(value)) {
21	        return `[${value.map((entry) => stableJsonValue(entry)).join(",")}]`;
22	      }
23	
24	      return `{${Object.keys(value)
25	        .sort()
26	        .map((key) => `${JSON.stringify(key)}:${stableJsonValue((value as Record<string, unknown>)[key])}`)
27	        .join(",")}}`;
28	    default:
29	      throw new Error(`Unsupported fingerprint input type: ${typeof value}`);
30	  }
31	}
32	
33	function fnv1a32(input: string): string {
34	  let hash = 0x811c9dc5;
35	  for (let index = 0; index < input.length; index += 1) {
36	    hash ^= input.charCodeAt(index);
37	    hash = Math.imul(hash, 0x01000193) >>> 0;
38	  }
39	  return hash.toString(16).padStart(8, "0");
40	}
41	
42	export function createReproducibilityFingerprint(
43	  settings: TrainingSettings,
44	): ReproducibilityFingerprint {
45	  const serializedSettings = stableJsonValue(settings);
46	  const digest = fnv1a32(`${APP_ALGORITHM_VERSION}:${serializedSettings}`);
47	
48	  return {
49	    appVersion: APP_ALGORITHM_VERSION,
50	    algorithmVersion: APP_ALGORITHM_VERSION,
51	    topology: settings.topology,
52	    randomSeed: settings.randomSeed,
53	    settingsDigest: digest,
54	    serializedSettings,
55	  };
56	}

