 36	      message: string;
 37	    }
 38	  | {
 39	      type: "cancelled";
 40	      requestId: number;
 41	    };
 42	
 43	interface PendingRequest {
 44	  resolve: (value: TrainingWorkerSuccessPayload) => void;
 45	  reject: (reason?: unknown) => void;
 46	  onProgress: ((progress: SomTrainingProgress) => void) | undefined;
 47	}
 48	
 49	export interface TrainingWorkerController {
 50	  train: (
 51	    settings: TrainingSettings,
 52	    options?: TrainRequestOptions,
 53	  ) => Promise<TrainingWorkerSuccessPayload>;
 54	  cancel: () => void;
 55	  dispose: () => void;
 56	}
 57	
 58	export function createTrainingWorker(): TrainingWorkerController {
 59	  const worker = new Worker(new URL("./training-worker.ts", import.meta.url), {
 60	    type: "module",
 61	  });
 62	
 63	  let nextRequestId = 1;
 64	  let activeRequestId: number | null = null;
 65	  let pendingRequest: PendingRequest | null = null;
 66	
 67	  worker.onmessage = (event: MessageEvent<TrainingWorkerResponse>) => {
 68	    const message = event.data;
 69	
 70	    if (message.requestId !== activeRequestId || !pendingRequest) {
 71	      return;
 72	    }
 73	
 74	    switch (message.type) {
 75	      case "progress":
 76	        pendingRequest.onProgress?.(message.progress);
 77	        break;
 78	      case "success":
 79	        pendingRequest.resolve({ result: message.result });
 80	        pendingRequest = null;
 81	        activeRequestId = null;
 82	        break;
 83	      case "cancelled":
 84	        pendingRequest.reject(new Error("Training cancelled."));
 85	        pendingRequest = null;
 86	        activeRequestId = null;
 87	        break;
 88	      case "error":
 89	        pendingRequest.reject(new Error(message.message));
 90	        pendingRequest = null;
 91	        activeRequestId = null;
 92	        break;
 93	    }
 94	  };
 95	
 96	  function postMessage(message: TrainingWorkerRequest): void {
 97	    worker.postMessage(message);
 98	  }
 99	
100	  return {
101	    train(settings, options) {
102	      if (pendingRequest) {
103	        pendingRequest.reject(new Error("A training request is already active."));
104	        pendingRequest = null;
105	        activeRequestId = null;
106	      }
107	
108	      const requestId = nextRequestId;
109	      nextRequestId += 1;
110	      activeRequestId = requestId;
111	
112	      return new Promise<TrainingWorkerSuccessPayload>((resolve, reject) => {
113	        pendingRequest = {
114	          resolve,
115	          reject,
116	          onProgress: options?.onProgress,
117	        };
118	
119	        postMessage({
120	          type: "train",
121	          requestId,
122	          settings,
123	        });
124	      });
125	    },
126	
127	    cancel() {
128	      if (activeRequestId === null) {
129	        return;
130	      }
131	
132	      postMessage({
