134	        requestId: activeRequestId,
135	      });
136	    },
137	
138	    dispose() {
139	      if (pendingRequest) {
140	        pendingRequest.reject(new Error("Training worker disposed."));
141	        pendingRequest = null;
142	      }
143	      activeRequestId = null;
144	      worker.terminate();
145	    },
146	  };
147	}

